            illustOriginal = `https://i.pximg.net/img-master/img/${date}/${illustId}_p0_master1200.jpg`
        } catch (e) {}
    }

    if (illustOriginal.split(",")[0] === "") return ""
    return this.urlCoverUrl(illustOriginal.replace(`_p0`, `_p${order - 1}`))
}
