    if (settings.IPDirect) {
        java.log("✈️ 直连模式：✅ 已开启")
    } else {
        java.log("✈️ 直连模式：❌ 已关闭")
    }
    u.settings = settings
    putInCacheObject("pixivIllustSettings", settings)  // 设置写入缓存

